import { OpenAI } from 'openai';
import { fromZodError } from 'instructor';
import { z } from 'zod';
import { vex } from 'vex-sdk';

const CaseSchema = z.object({
  citation: z.string().regex(/^[A-Z]+ v\. [A-Z]+/),  // Real citation
  jurisdiction: z.enum(['NY', 'CA', 'Federal']),
  privileged: z.boolean()
});

type Case = z.infer<typeof CaseSchema>;

const client = new OpenAI();
const extractCase = vex.verify(
  async (prompt: string): Promise<Case> => {
    const completion = await client.chat.completions.create({
      model: 'gpt-4o',
      response_format: { type: 'json_schema', json_schema: { name: 'case', strict: true, schema: CaseSchema } },
      messages: [{ role: 'user', content: prompt }]
    });
    return CaseSchema.parse(JSON.parse(completion.choices[0].message.content || '{}'));
  },
  { mode: 'retry' }
);

extractCase('Extract: Mata v. Avianca, Federal, privileged: true');

from instructor import from_openai
from pydantic import BaseModel
from typing import List
import vex

class Document(BaseModel):
    doc_id: str
    privileged: bool
    parties: List[str]

class eDiscoverySet(BaseModel):
    case_name: str
    documents: List[Document]

client = from_openai(OpenAI())
@vex.verify(max_retries=3)
def extract_ediscovery(prompt: str) -> eDiscoverySet:
    return client.chat.completions.create(
        model="gpt-4o",
        response_model=eDiscoverySet,
        messages=[{"role": "user", "content": prompt}]
    )

response = extract_ediscovery("eDiscovery set: Mata v. Avianca, docs: [id:001 privileged:true parties:['Mata','Avianca']]" )
